const body = $input.first().json.body || {};

let data = {};
if (body.jsonData) {
  if (typeof body.jsonData === 'string') {
    try {
      data = JSON.parse(body.jsonData);
    } catch (e) {
      data = {};
    }
  } else if (typeof body.jsonData === 'object') {
    data = body.jsonData;
  }
}

return [{
  json: {
    ...data,
    body: body
  }
}];

